import React, { useState } from "react";
import axios from "axios";
import Swal from "sweetalert2";
import { XMarkIcon } from "@heroicons/react/24/solid";

export default function EditProfile({ user, closeModal, onUpdated }) {
  const [name, setName] = useState(user?.name || "");
  const [imageFile, setImageFile] = useState(null);
  const [preview, setPreview] = useState(user?.profileImage || "");

  const [currentPassword, setCurrentPassword] = useState("");
  const [newPassword, setNewPassword] = useState("");

  // IMAGE
  const handleImageChange = (e) => {
    const file = e.target.files[0];
    if (!file) return;

    setImageFile(file);

    const reader = new FileReader();
    reader.onloadend = () => setPreview(reader.result);
    reader.readAsDataURL(file);
  };

  // UPDATE PROFILE
  const handleUpdateProfile = async () => {
    try {
      const formData = new FormData();
      formData.append("email", user.email);
      formData.append("name", name);

      if (imageFile) {
        formData.append("image", imageFile);
      }

      const res = await axios.put(
        "http://localhost:8086/user/update-profile",
        formData
      );

      Swal.fire("Success", "Profile updated", "success");

      localStorage.setItem("user", JSON.stringify(res.data));
      onUpdated(res.data); // update parent
      closeModal();

    } catch (err) {
      Swal.fire("Error", "Update failed", "error");
    }
  };

  // PASSWORD
  const handleChangePassword = async () => {
    try {
      const res = await axios.put(
        "http://localhost:8086/user/change-password",
        {
          email: user.email,
          currentPassword,
          newPassword,
        }
      );

      Swal.fire("Success", res.data.message, "success");

      setCurrentPassword("");
      setNewPassword("");
    } catch (err) {
      Swal.fire("Error", "Password update failed", "error");
    }
  };

  return (
    <div className="fixed inset-0 flex items-center justify-center z-50">

      {/* BACKDROP */}
      <div
        className="absolute inset-0 bg-black/40 backdrop-blur-sm"
        onClick={closeModal}
      />

      {/* MODAL */}
      <div className="relative w-[520px] p-6 rounded-2xl backdrop-blur-xl bg-white/20 border border-white/30 shadow-2xl">

        {/* CLOSE */}
        <button
          onClick={closeModal}
          className="absolute top-3 right-3 text-gray-700 hover:text-red-500"
        >
          <XMarkIcon className="w-6 h-6" />
        </button>

        <h2 className="text-xl font-bold text-center mb-4">
          ✨ Edit Profile
        </h2>

        {/* IMAGE */}
        <div className="flex flex-col items-center mb-4">
          <img
            src={preview}
            className="w-24 h-24 rounded-full border-4 border-white"
            alt="preview"
          />

          <input
            type="file"
            onChange={handleImageChange}
            className="mt-3 text-sm"
          />
        </div>

        {/* NAME */}
        <input
          value={name}
          onChange={(e) => setName(e.target.value)}
          className="w-full p-2 rounded-lg bg-white/30 border mb-3"
          placeholder="Name"
        />

        <button
          onClick={handleUpdateProfile}
          className="w-full bg-indigo-500 text-white py-2 rounded-lg mb-4"
        >
          Save Changes
        </button>

        {/* PASSWORD */}
        <div className="border-t pt-4">

          <input
            type="password"
            placeholder="Current Password"
            value={currentPassword}
            onChange={(e) => setCurrentPassword(e.target.value)}
            className="w-full p-2 mb-2 rounded-lg bg-white/30"
          />

          <input
            type="password"
            placeholder="New Password"
            value={newPassword}
            onChange={(e) => setNewPassword(e.target.value)}
            className="w-full p-2 mb-3 rounded-lg bg-white/30"
          />

          <button
            onClick={handleChangePassword}
            className="w-full bg-purple-500 text-white py-2 rounded-lg"
          >
            Update Password
          </button>

        </div>
      </div>
    </div>
  );
}
